mobileNavigation.flutter:
BottomNavigationBar(
  currentIndex: currentIndex,
  onTap: onTabTapped,
  type: BottomNavigationBarType.fixed,
  selectedItemColor: theme.colorScheme.primary,
  unselectedItemColor: theme.colorScheme.onSurface.withOpacity(0.6),
  items: AppTab.values.map((tab) {
    return BottomNavigationBarItem(
      icon: Icon(tab.icon),
      label: tab.label,
      tooltip: tab.tooltip,
    );
  }).toList(),
)

tabletNavigation.flutter:
Row(
  children: [
    NavigationRail(
      selectedIndex: currentIndex,
      onDestinationSelected: onTabTapped,
      labelType: NavigationRailLabelType.all,
      backgroundColor: theme.colorScheme.surfaceContainerHighest,
      selectedIconTheme: IconThemeData(color: theme.colorScheme.primary),
      unselectedIconTheme: IconThemeData(
        color: theme.colorScheme.onSurface.withOpacity(0.6),
      ),
      destinations: AppTab.values.map((tab) {
        return NavigationRailDestination(
          icon: Icon(tab.icon),
          label: Text(tab.label),
        );
      }).toList(),
    ),
    VerticalDivider(thickness: 1, width: 1),
    Expanded(
      child: Scaffold(
        appBar: AppBar(title: Text(currentTab.title)),
        body: currentTab.content,
      ),
    ),
  ],
)

desktopNavigation.flutter:
Row(
  children: [
    NavigationRail(
      minWidth: 80,
      selectedIndex: currentIndex,
      onDestinationSelected: onTabTapped,
      labelType: NavigationRailLabelType.all,
      iconTheme: IconThemeData(size: 28),
      destinations: AppTab.values.map((tab) {
        return NavigationRailDestination(
          icon: Icon(tab.icon, size: 28),
          label: Text(tab.label),
        );
      }).toList(),
    ),
    VerticalDivider(thickness: 1, width: 1),
    if (currentTab == AppTab.storage)
      Sidebar(width: 240, child: FilterPanel()),
    Expanded(
      child: Center(
        child: ConstrainedBox(
          constraints: BoxConstraints(maxWidth: 800),
          child: currentTab.content,
        ),
      ),
    ),
  ],
)

adaptiveBreakpoints.flutter:
class Breakpoints {
  static const double mobileMax = 600;
  static const double tabletMin = 600;
  static const double desktopMin = 900;
  static const double wideMin = 1200;
}

stateManagement.flutter:
class _AdaptiveNavigationState extends State<AdaptiveNavigation> {
  int _currentIndex = 0;

  void _onTabTapped(int index) {
    setState(() {
      _currentIndex = index;
    });
    widget.tabs[index].navigate(context);
  }
}
